mapper.select:
select
	v.activityalias_                 ,
	v.businessstate_                 ,
	t1.id                             ,
	t1.secret_level                   ,
	t1.project_id                     ,
	t1.project_name                   ,
	t1.project_order                  ,
	t1.org_model                      ,
	t1.user_id                        ,
	t1.dept_id                        ,
	t1.leader_dept                    ,
	t1.project_leader                 ,
	t1.company_manager_id             ,
	t1.science_user_id                ,
	t1.plan_start_date                ,
	t1.plan_end_date                  ,
	t1.fund_budget                    ,
	t1.fund_expenditure               ,
	t1.project_node                   ,
	t1.this_month_plan                ,
	t1.next_month_plan                ,
	t1.this_month_xtwt                ,
	t1.this_month_cyuser              ,
	t1.expense_execution_rate         ,
	t1.fund_execution_rate            ,
	t1.plan_status                    ,
	t1.wr_year                        ,
	t1.wr_month                       ,
	t1.status                         ,
	t1.bpm_task_id                    ,
	t1.remark                         ,
	t1.created_by                     ,
	t1.creation_date                  ,
	t1.last_updated_by                ,
	t1.last_update_date               ,
	t1.last_update_ip                 ,
	t1.version                        ,
	t1.created_dept                   ,
	t1.org_identity                   ,
	t1.attribute_01                   ,
	t1.attribute_02                   ,
	t1.attribute_03                   ,
	t1.attribute_04                   ,
	t1.attribute_05                   ,
	t1.attribute_06                   ,
	t1.attribute_07                   ,
	t1.attribute_08                   ,
	t1.attribute_09                   ,
	t1.attribute_10                   
from pm_project_workreport 	t1 left join bpm_client_hist_procinst_v v on t1.id = v.formid_ 


			and t1.ID =#{id}


			and t1.SECRET_LEVEL =#{secretLevel}


			and t1.PROJECT_ID =#{projectId}


			and t1.PROJECT_NAME =#{projectName}


			and t1.PROJECT_ORDER =#{projectOrder}


			and t1.ORG_MODEL =#{orgModel}


			and t1.USER_ID =#{userId}


			and t1.DEPT_ID =#{deptId}


			and t1.LEADER_DEPT =#{leaderDept}


			and t1.PROJECT_LEADER =#{projectLeader}


			and t1.COMPANY_MANAGER_ID =#{companyManagerId}


			and t1.SCIENCE_USER_ID =#{scienceUserId}


			and t1.PLAN_START_DATE >= #{planStartDateBegin}


			and t1.PLAN_START_DATE <= #{planStartDateEnd}


			and t1.PLAN_END_DATE >= #{planEndDateBegin}


			and t1.PLAN_END_DATE <= #{planEndDateEnd}


			and t1.FUND_BUDGET =#{fundBudget}


			and t1.FUND_EXPENDITURE =#{fundExpenditure}


			and t1.PROJECT_NODE =#{projectNode}


			and t1.THIS_MONTH_PLAN =#{thisMonthPlan}


			and t1.NEXT_MONTH_PLAN =#{nextMonthPlan}


			and t1.THIS_MONTH_XTWT =#{thisMonthXtwt}


			and t1.THIS_MONTH_CYUSER =#{thisMonthCyuser}


			and t1.EXPENSE_EXECUTION_RATE =#{expenseExecutionRate}


			and t1.FUND_EXECUTION_RATE =#{fundExecutionRate}


			and t1.PLAN_STATUS =#{planStatus}


			and t1.WR_YEAR =#{wrYear}


			and t1.WR_MONTH =#{wrMonth}


			and t1.STATUS =#{status}


			and t1.BPM_TASK_ID =#{bpmTaskId}


			and t1.REMARK =#{remark}


			and t1.CREATED_BY =#{createdBy}


			and t1.CREATION_DATE =#{creationDate}


			and t1.LAST_UPDATED_BY =#{lastUpdatedBy}


			and t1.LAST_UPDATE_DATE =#{lastUpdateDate}


			and t1.LAST_UPDATE_IP =#{lastUpdateIp}


			and t1.VERSION =#{version}


			and t1.CREATED_DEPT =#{createdDept}


			and t1.ORG_IDENTITY =#{orgIdentity}


			and t1.ATTRIBUTE_01 =#{attribute01}


			and t1.ATTRIBUTE_02 =#{attribute02}


			and t1.ATTRIBUTE_03 =#{attribute03}


			and t1.ATTRIBUTE_04 =#{attribute04}


			and t1.ATTRIBUTE_05 =#{attribute05}


			and t1.ATTRIBUTE_06 =#{attribute06}


			and t1.ATTRIBUTE_07 =#{attribute07}


			and t1.ATTRIBUTE_08 =#{attribute08}


			and t1.ATTRIBUTE_09 =#{attribute09}


			and t1.ATTRIBUTE_10 =#{attribute10}


			 and exists (select 1 from BPM_CLIENT_HIST_TASK_V os where os.task_b_id_ = t1.id and os.assignee_ = #{currUserId}) 


			and v.businessstate_ = #{bpmState}
